var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"감옥에 갇힌 죄수들은 죄목으로 자기들 사이에서 급을 나눠.","JPN":"刑務所に入った囚人たちは、罪の重さでランク付けをする。","ENG":"In prison, the inmates discriminate among each other based on their charges.","TWN":"被關在監獄裡的囚犯會以罪名分等級。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"선량한 시민들 눈에는 다 죽일 놈들인데, 살인자는 피해야 될 놈이고 아동 납치범은 맞아도 싼 놈 취급 받지.","JPN":"善良な市民からしたら全員凶悪な犯罪者なのに、人殺しは避けるべき者で、児童誘拐犯は殴られて当然の扱いをされる。","ENG":"To innocent civilians, they are all just criminals. But they too avoid murderers, and think it's fair game to beat up pedophiles anytime they want.","TWN":"他們都是罪該萬死的人，但在善良的市民眼中，殺人犯是需要避開的人，而兒童綁架犯就算挨打也不會得到原諒。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"남의 자식 목숨 값 흥정하는 건 더럽고, 배신자의 일가족을 물고기 밥으로 만드는 건 대단한가?","JPN":"他人の子どもの命を利用するのは汚らわしいことで、裏切り者の一家を魚の餌にするのは見事なことだって？","ENG":"But who's to say what crime is worthy of respect and what's worthy of disdain?","TWN":"用別人孩子的性命討價還價是骯髒的行為，但把背叛者一家丟去餵魚就了不起了嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"사실은 다들 알고 있어.","JPN":"実はみんなわかっているんだ。","ENG":"Everyone knows there's no difference.","TWN":"其實大家都知道。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그냥 걱정 없이 물어뜯으면서 스트레스 풀 샌드백이 필요해서지.","JPN":"ただ心置きなく噛みちぎってストレスを発散できるサンドバッグが必要なだけ。","ENG":"They just want a punching bag to relieve their stress upon.","TWN":"他們不過是需要一個可以放心抒發壓力的沙包而已……？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 그 연놈들한테 유난스럽게 굴었던 것도......","JPN":"私があいつらに大げさになっていたのも……","ENG":"I was probably extra dramatic with those fools...","TWN":"我特別對待的那對狗男女也……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"아마 비슷한 이유였을 거야.","JPN":"おそらく似たような理由だろう。","ENG":"... for a similar reason.","TWN":"大概也是差不多的理由吧。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"어윽......!","JPN":"くっ……！","ENG":"Ugh!","TWN":"呃……！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"다...... 다짜고짜 사람을 끌고 와? 당신 이거 범죄야!","JPN":"む……無理やり人を連れていくなんて、これは立派な犯罪だぞ！","ENG":"Hey... You can't just drag us out here! This is a crime, you know!","TWN":"就……就這樣不分青紅皂白的把人拉過來？你這樣是犯罪！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"맞아! 그 자리는 우리가 사흘 전부터 찍어 뒀던 명당이라고!","JPN":"そうよ！　あそこは私たちが3日前から狙っていたアタリの場所なの！","ENG":"That's right! We had dibs on that spot three days ago!","TWN":"對！那個位置是我們三天前就定好的地方！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"거기서 몇 명이 대박을 터뜨렸는데......!","JPN":"そこで何人も大勝ちしたと聞いて……！　","ENG":"So many people hit the jackpot there!","TWN":"坐在那裡有好幾個人都發大財了……！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":" 끄윽......!","JPN":"くうっ……！","ENG":" Ow!","TWN":"呃啊……！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"여, 여보!","JPN":"あ、あなた！","ENG":"H-honey!","TWN":"老、老婆！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 댁들처럼 간이 배 밖으로 나온 인간들이 제일 신기해.","JPN":"私はな、お前らみたいな人間が一番不思議でしょうがないんだ。","ENG":"I'm always amazed by how quickly people forget fear.","TWN":"我很好奇你們這些膽大包天的人類。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 도박이 좋나? 지난달에는 욕조에서 입수도 시켜 줬는데?","JPN":"そんなにギャンブルが好きか？　先月みたいにまた水責めにされたいのか？","ENG":"Do you love gambling that much? Even after I water-boarded you last month?","TWN":"就那麼想發財？上個月才被我按在浴缸裡醒腦！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무튼, 이번 달치 상환금은 약속대로 내놓으셔야겠어.","JPN":"とにかく、今月分の償還金は約束どおりもらうぞ。","ENG":"In any case, you'd better cough up this month's payment as promised.","TWN":"總之，這個月的還款一定要如期交出來。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그, 글쎄 따서 갚는다니까......","JPN":"だ、だから勝ったら返すって……","ENG":"W-we will, once we win some money...","TWN":"我、我們贏了錢就還……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};